const file = penpot.currentFile;
const current = penpot.currentPage;
const pages = file.pages.map(p => ({ id: p.id, name: p.name }));
const lib = penpot.library.local;
function collect(page) {
  const root = page.root || page;
  const all = penpotUtils.findShapes(() => true, root);
  const boards = all.filter(s => s.type === 'board').map(s => ({ id: s.id, name: s.name, x: s.x, y: s.y, w: s.width, h: s.height }));
  const texts = all.filter(s => s.type === 'text').map(s => ({ id: s.id, name: s.name, text: s.characters || s.text || '', x: s.x, y: s.y, w: s.width, h: s.height, growType: s.growType, fontSize: s.fontSize, verticalAlign: s.verticalAlign, align: s.align }));
  return { page: page.name, boards, texts };
}
const sourcePage = file.pages.find(p => p.name === 'Assets / Component Sources');
const relevantPages = file.pages.filter(p => ['Assets / Component Sources','Foundations','Mobile','Tablet','Web','Widgets'].includes(p.name));
return {
  currentPage: current && current.name,
  pages,
  components: lib.components.length,
  colors: lib.colors.length,
  typographies: lib.typographies.length,
  source: sourcePage ? collect(sourcePage) : null,
  pageSummaries: relevantPages.map(p => ({ name: p.name, rootChildren: (p.root || p).children ? (p.root || p).children.length : null }))
};

